#include <bits/stdc++.h>
using namespace std;

int solve() {
    int n;
    cin >> n;
    vector<vector<int>> board(n, vector<int>(n));

    // Input board
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
            cin >> board[i][j];
        }
    }

    // Create cells mapping
    vector<pair<int,int>> cells(n*n + 1);
    int cell = 1;
    bool leftToRight = true;

    for(int i = n-1; i >= 0; i--) {
        if(leftToRight) {
            for(int j = 0; j < n; j++) {
                cells[cell++] = {i, j};
            }
        } else {
            for(int j = n-1; j >= 0; j--) {
                cells[cell++] = {i, j};
            }
        }
        leftToRight = !leftToRight;
    }

    // BFS
    vector<int> dist(n*n + 1, -1);
    queue<int> q;
    dist[1] = 0;
    q.push(1);

    while(!q.empty()) {
        int curr = q.front();
        q.pop();

        for(int next = curr + 1; next <= min(curr + 6, n*n); next++) {
            auto [row, col] = cells[next];
            int dest = board[row][col] != -1 ? board[row][col] : next;

            if(dist[dest] == -1) {
                dist[dest] = dist[curr] + 1;
                q.push(dest);
            }
        }
    }

    return dist[n*n];
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        cout << solve() << endl;
    }
    return 0;
}
